import{_ as a,c as i,a as t,o as s}from"./app-CEcM0piI.js";const n={};function r(l,e){return s(),i("div",null,e[0]||(e[0]=[t('<p>当要实现一个与类基本功能不相干的功能时(如:一个类的方法需要有日志功能) 直接将功能写入到类的函数中时会使函数多了许多不相干的功能不方便阅读 可以设置一个静态代理类,在这个类中实现额外功能并使用它调用相应的功能,但这样依旧会有许多冗余代码</p><h1 id="动态代理" tabindex="-1"><a class="header-anchor" href="#动态代理"><span>动态代理</span></a></h1><p>当一个类需要添加新功能的时候可以直接在它的类里面添加成员函数,这样的修改称为侵入式修改</p><p>动态代理可以无侵入式的给代码增加额外的功能 对象如果嫌身上干的事太多就可以通过代理来转移部分职责,这样让类专注于自己功能</p><p><strong>创建代理对象</strong></p><ul><li>参数一：用于指定用哪个类加载器，去加载生成的代理类</li><li>参数二：指定接口，这些接口用于指定生成的代理长什么，也就是有哪些方法</li><li>参数三：用来指定生成的代理对象要干什么事情</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public static Object newProxyInstance(ClassLoader loader，Class&lt;?&gt;[] interfaces,InvocationHandler h)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>',7)]))}const d=a(n,[["render",r]]),o=JSON.parse('{"path":"/back/java/9/","title":"9 动态代理","lang":"zh-CN","frontmatter":{"title":"9 动态代理","createTime":"2025/04/05 12:12:26","permalink":"/back/java/9/"},"readingTime":{"minutes":1.08,"words":323},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Java/9 动态代理.md","headers":[]}');export{d as comp,o as data};
